VALUES
  ('cpa-moex-00911', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司之營業週期為2年。其20X1年財務報表於20X2年3月底通過發布，下列何者應在20X1年 12月31日之資產負債表列為非流動負債？', '["20X3年2月到期之銀行借款", "20X1年11月底宣告並預計於20X4年1月發放之應分配股票股利", "20X1年底取得不動產、廠房及設備資產所認列之除役成本負債準備", "20X2年3月底到期，但已於20X2年1月底完成5年期限再融資協議之金融負債 預計20X2年6月收款之應收外幣帳款，於20X1年底認列之未實現兌換利益所產生之遞延所得稅 負債"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00912', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '某地方政府為鼓勵甲公司增進當地居民的就業機會，依相關獎勵辦法提供低利貸款給甲公司。根據 貸款合約，地方政府於 20X1 年 1 月 1 日撥款$10,000,000 予甲公司，並接受甲公司開立面額 $10,000,000，票面利率2%，每年底付息之3年期票據，當日之市場利率為10%。甲公司採曆年制， 按有效利息法將票面利率與市場利率差額攤銷認列政府補助收入，此項低利貸款合約對甲公司相關 年度財報之影響何者正確？', '["甲公司於20Xl年1月1日應認列相關負債$10,000,000", "甲公司於20Xl年度應認列補助收入$800,000", "此合約於低利貸款期間，對甲公司每年之損益淨影響數將會相同", "於低利貸款期間，甲公司對此合約每年度認列之利息費用會相同 於低利貸款期間，甲公司對此合約每年底應報導之相關負債總金額會相同"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00913', 'cpa', 'cpa-moex-106-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司設有一確定福利退休計畫，於每年年底提撥現金至退休金專戶及自專戶支付退休福利。 20X1年1月1日，確定福利義務現值為$690,000，計畫資產公允價值為$570,000；20X1年12月 31日，確定福利義務現值為$919,000，計畫資產公允價值為$680,000。20X1年底，甲公司修改退休 金計畫，且產生前期服務成本。20X1 年，甲公司提撥至退休金專戶之金額為$200,000，當期服務成 本為$180,000，折現率為10%，該計畫資產實際報酬為$30,000。下列有關20X1年該確定福利退休計 畫之敘述何者正確？', '["前期服務成本$100,000", "支付退休福利$120,000", "淨確定福利負債淨利息$69,000", "損益表應表達之相關損益$192,000 淨確定福利負債增加$119,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "ea4ee0145b00", "answer_pdf_sha1": "34786ebea20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00914', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'essay', 'A 股份有限公司（下稱 A 公司），為非公開發行公司，在本年度股東常會中將採
行電子方式行使其表決權，並有將行使方法載明於股東會召集通知。股東甲因當日
有公務在身無法親身出席參與股東會討論，因此在股東會開會前七日，將其意思表
示送達 A 公司。然而甲擔心電子系統臨時出狀況，加上本次常會討論之議案，事
關股東權益重大，因此又另外以自行書寫的委託書，委託他人代理出席此次股東常
會。試問：股東會電子投票制度是否仍需要召開實體會議？甲可否以「自行書寫」
的委託書委託他人代理出席？甲以電子方式投票，又以委託書委託代理人出席，究
應以何者為準以發生效力？請回答並詳細說明。（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00915', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'essay', 'A 上櫃公司（下稱 A 公司）專門生產 LED 燈具，該公司實收資本額達新臺幣 15
億元。試依證券交易法相關規定，附理由回答下列問題：
該公司為採高標準之公司治理，故設置審計委員會，惟欲同時保留監察人，此舉
是否合法？（4分）
A 公司依法設置審計委員會時，特別注意到法令遵循之趨勢，故全體審計委員
會成員均為法務專長，如此是否適法？（8分）
A 公司依法設置審計委員會後，該公司隨即修正內部控制制度，惟僅經審計委
員會全體成員三分之一的同意，故該公司董事長甲另召集董事會，經過半數之全
體董事同意前開修正，如此董事會決議是否合法？（8分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00916', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'essay', '何謂「原始憑證」與「記帳憑證」？兩者之關係為何？有何例外？（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00917', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '以文具製造為業之A公司，其實收股本為新臺幣（下同）1000萬元，公司淨值為1600萬元，A公司章 程對公司轉投資無任何規定，目前A公司已投資B公司200萬元，今A公司董事會擬自行決定再對C公 司進行轉投資，則A公司可投資於C公司之金額上限為多少？', '["200萬元", "400萬元", "440萬元", "640萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00918', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A有限公司，其資本額為新臺幣（下同）130萬元，有甲（出資40萬元）、乙（出資30萬元）、丙（出 資30萬元）、丁（出資20萬元）及戊（出資10萬元）共5位股東，公司章程規定設董事一人，但對股 東表決權之行使、公司解散事由等無特別規定，目前董事由甲擔任之。乙擬將其出資全部轉讓給庚，下 列敘述，何者正確？', '["乙之出資轉讓應經其他股東至少3名之同意", "乙之出資轉讓應經出資合計超過50萬元之其他股東的同意", "乙之出資轉讓應經其他全體股東之同意", "乙出資之轉讓對象限於公司其他股東，因此不得轉讓給庚"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00919', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A股份有限公司（下稱A公司）為上市公司，A公司對其董事違反公司法第23條規定，所得行使之歸入 權其期間最長不得超過下列何者？', '["3個月", "6個月", "1年", "2年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00920', 'cpa', 'cpa-moex-106-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於公司減少資本以現金以外財產退還股款之敘述，下列何者正確？', '["退還財產之種類，由董事會以決議決定之", "退還財產抵充股款之數額，應經股東會特別決議", "退還之財產及抵充之數額，應經該收受財產股東之同意", "退還財產之價值及抵充之數額，董事會應於股東會前，報請主管機關核定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "21d00306ef40", "answer_pdf_sha1": "dd265de3c045", "source_family": "moex-gov-tw", "moex": {"exam_code": "106140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "106", "exam_name": "106年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
